import * as core from '@actions/core';
import { findExistingStackDetails, getClient, getContext, getStackDetails, getUserAgent, snooze, waitForDeployment, } from '@chanzuckerberg/argus-ci-shared';
import * as github from '@actions/github';
export function getInputs() {
    return core.group('Gathering inputs', async () => {
        const waitForDeploymentSeconds = parseInt(core.getInput('waitForDeploymentSeconds', { required: true }), 10);
        if (Number.isNaN(waitForDeploymentSeconds)) {
            throw new Error('waitForDeploymentSeconds must be a number');
        }
        const postStackDetailsRaw = core.getInput('postStackDetails', { required: false }) || 'body';
        let postStackDetails;
        // Handle backwards compatibility with old boolean values (postStackDetails used to be a boolean)
        if (postStackDetailsRaw === 'true') {
            postStackDetails = 'body';
        }
        else if (postStackDetailsRaw === 'false') {
            postStackDetails = 'none';
        }
        else if (postStackDetailsRaw === 'body' || postStackDetailsRaw === 'comment' || postStackDetailsRaw === 'none') {
            postStackDetails = postStackDetailsRaw;
        }
        else {
            throw new Error(`postStackDetails must be 'body', 'comment', or 'none', got '${postStackDetailsRaw}'`);
        }
        const inputs = {
            dryRun: core.getBooleanInput('dryRun', { required: false }),
            appName: core.getInput('appName', { required: true }),
            envName: core.getInput('envName', { required: true }),
            githubToken: core.getInput('githubToken', { required: true }),
            waitForDeploymentSeconds,
            postStackDetails,
        };
        core.info(`Received CREATE event: ${JSON.stringify(inputs, null, 2)}`);
        return inputs;
    });
}
async function main() {
    const inputs = await getInputs();
    const context = getContext();
    await core.group('Log context', async () => {
        core.info(`Context: ${JSON.stringify(context, null, 2)}`);
        core.info(`User Agent: ${getUserAgent(context)}`);
    });
    if (inputs.dryRun) {
        core.warning('Dry Run: Skipping create');
        return;
    }
    const client = await getClient(context);
    const branchName = context.branch;
    const requestLogMessage = `Requesting to create stack with git_branch=${branchName} in app=${inputs.appName} env=${inputs.envName}`;
    const data = await core.group(requestLogMessage, async () => {
        const resp = await client.POST('/v1/deployments/createStack', {
            params: {
                header: { Authorization: '' }, // real token added by middleware
            },
            body: {
                appName: inputs.appName,
                envName: inputs.envName,
                gitBranch: branchName,
            },
        });
        if (resp.error) {
            throw new Error(`failed to create stack with git_branch=${branchName}: ${JSON.stringify(resp.error)}`);
        }
        core.info(`> Received response: ${JSON.stringify(resp.data, null, 2)}`);
        return resp.data;
    });
    core.info(`> Successfully created stack:\n - name: ${data.name}\n - base url: ${data.base_url}`);
    if (inputs.postStackDetails !== 'none' && context.eventName === 'pull_request' && inputs.githubToken.length > 0) {
        const stackDetails = await core.group('Getting stack details', async () => {
            const stackDetailsResp = await client.GET('/v1/deployments/getStackInfoByName', {
                params: {
                    query: {
                        appName: inputs.appName,
                        envName: inputs.envName,
                        stackName: data.name,
                    },
                    header: { Authorization: '' }, // real token added by middleware
                },
            });
            if (stackDetailsResp.error) {
                throw new Error(`failed to get stack details: ${JSON.stringify(stackDetailsResp.error)}`);
            }
            core.info(`> Received stack details: ${JSON.stringify(stackDetailsResp.data, null, 2)}`);
            return stackDetailsResp.data;
        });
        if (inputs.postStackDetails === 'comment') {
            await core.group('Posting stack details as PR comment', async () => writeStackDetailsAsComment(context, inputs, data.name, data.base_url, stackDetails.argo.url, stackDetails.grafana.dashboard_url));
        }
        else {
            await core.group('Updating PR body with stack details', async () => writeStackDetailsToPRBody(context, inputs, data.name, data.base_url, stackDetails.argo.url, stackDetails.grafana.dashboard_url));
        }
    }
    if (inputs.waitForDeploymentSeconds > 0) {
        await core.group(`Waiting up to ${inputs.waitForDeploymentSeconds} seconds for deployment to complete...`, async () => {
            // Sleep for 5 seconds to allow the deployment to start. Without this we may see an error because ArgoCD
            // has not yet created the deployment object and/or the ArgoCD App doesn't have any revisions in the history yet.
            await snooze(5000);
            await waitForDeployment(client, inputs.appName, inputs.envName, branchName, inputs.waitForDeploymentSeconds, context.gitSha);
        });
    }
    core.setOutput('stackName', data.name);
    core.setOutput('baseURL', data.base_url);
}
async function writeStackDetailsToPRBody(context, inputs, stackName, stackBaseURL, argocdApplicationURL, grafanaDashboardURL) {
    if (!context.pullRequestNumber) {
        throw new Error('No pull request number found in context');
    }
    const [owner, repo] = context.repo.split('/');
    const gitClient = github.getOctokit(inputs.githubToken);
    const issueResult = await gitClient.rest.issues.get({
        owner,
        repo,
        issue_number: context.pullRequestNumber,
    });
    const pullRequest = issueResult.data;
    let prBody = pullRequest.body || '';
    const stackDetailsCtx = { argusBaseUrl: context.argusBaseUrl, appName: inputs.appName, envName: inputs.envName };
    const newArgusStackDetails = getStackDetails({
        ctx: stackDetailsCtx,
        stackName,
        stackBaseURL,
        argocdApplicationURL,
        grafanaDashboardURL,
    });
    const existingArgusStackDetails = findExistingStackDetails(stackDetailsCtx, prBody);
    if (existingArgusStackDetails) {
        core.info('> Found existing Argus stack details in PR body, replacing it with the new one...');
        prBody = prBody.replace(existingArgusStackDetails, newArgusStackDetails);
    }
    else {
        core.info('> No existing Argus stack details found in PR body, adding a new one...');
        prBody = newArgusStackDetails + prBody;
    }
    gitClient.rest.issues.update({
        owner,
        repo,
        issue_number: context.pullRequestNumber,
        body: prBody,
    });
}
async function writeStackDetailsAsComment(context, inputs, stackName, stackBaseURL, argocdApplicationURL, grafanaDashboardURL) {
    if (!context.pullRequestNumber) {
        throw new Error('No pull request number found in context');
    }
    const [owner, repo] = context.repo.split('/');
    const gitClient = github.getOctokit(inputs.githubToken);
    const stackDetailsCtx = { argusBaseUrl: context.argusBaseUrl, appName: inputs.appName, envName: inputs.envName };
    const newArgusStackDetails = getStackDetails({
        ctx: stackDetailsCtx,
        stackName,
        stackBaseURL,
        argocdApplicationURL,
        grafanaDashboardURL,
    });
    // Find existing comment with stack details to update instead of creating a new one
    // Skip comments showing "Argus Stack Deleted" - those should remain as historical records
    const comments = await gitClient.rest.issues.listComments({
        owner,
        repo,
        issue_number: context.pullRequestNumber,
    });
    const existingComment = comments.data.find((comment) => comment.body
        && findExistingStackDetails(stackDetailsCtx, comment.body)
        && !comment.body.includes('Argus Stack Deleted'));
    if (existingComment) {
        core.info('> Found existing Argus stack details comment, updating it...');
        await gitClient.rest.issues.updateComment({
            owner,
            repo,
            comment_id: existingComment.id,
            body: newArgusStackDetails,
        });
    }
    else {
        core.info('> No existing Argus stack details comment found, creating a new one...');
        await gitClient.rest.issues.createComment({
            owner,
            repo,
            issue_number: context.pullRequestNumber,
            body: newArgusStackDetails,
        });
    }
}
if (process.env.NODE_ENV !== 'test') {
    main();
}
